class Solution {
public:
    int subarrayGCD(vector<int>& nums, int k) {
        int count = 0;
        for (int i = 0; i < nums.size(); ++i) {
            int gcd = nums[i];
            if (gcd == k) ++count;
            for (int j = i + 1; j < nums.size(); ++j) {
                gcd = gcdHelper(gcd, nums[j]);
                if (gcd == k) ++count;
                if (gcd < k) break;
            }
        }
        return count;
    }

    int gcdHelper(int a, int b) {
        if (b == 0) return a;
        return gcdHelper(b, a % b);
    }
};
